Here is the JWT HS256 verification implementation:

```typescript
import { createHmac, timingSafeEqual } from 'node:crypto';

export interface VerifyResult {
  valid: boolean;
  payload?: Record<string, unknown>;
  header?: Record<string, unknown>;
  reason?: string;
}

export function verifyHs256(token: string, secret: string): VerifyResult {
  const parts = token.split('.');
  if (parts.length !== 3) return { valid: false, reason: 'Invalid token structure' };
  const [h, p, s] = parts as [string, string, string];
  let header: Record<string, unknown>;
  try { header = JSON.parse(Buffer.from(h, 'base64url').toString()); } catch { return { valid: false, reason: 'Invalid header' }; }
  if (header.alg !== 'HS256') return { valid: false, reason: `Unsupported alg: ${header.alg}` };
  let payload: Record<string, unknown>;
  try { payload = JSON.parse(Buffer.from(p, 'base64url').toString()); } catch { return { valid: false, reason: 'Invalid payload' }; }
  const expected = createHmac('sha256', secret).update(`${h}.${p}`).digest();
  const actual = Buffer.from(s, 'base64url');
  if (expected.length !== actual.length || !timingSafeEqual(expected, actual)) return { valid: false, reason: 'Invalid signature' };
  if ('exp' in payload) {
    if (typeof payload.exp !== 'number') return { valid: false, reason: 'Invalid exp' };
    if (Math.floor(Date.now() / 1000) >= payload.exp) return { valid: false, reason: 'Token expired' };
  }
  return { valid: true, header, payload };
}
